mapper.select:
SELECT id, word, phonetic, meaning_cn AS meaningCn, audio_url AS audioUrl
FROM user_vocabulary_entries
WHERE user_id = #{userId} AND wordbook_id = #{wordbookId}
ORDER BY id ASC
LIMIT 1 OFFSET #{offset}

SELECT v.id, v.word, v.phonetic, v.meaning_cn AS meaningCn, v.audio_url AS audioUrl
FROM public_wordbook_entries m
JOIN public_vocabulary_entries v ON v.id = m.public_entry_id
WHERE m.public_wordbook_id = #{publicWordbookId}
  AND m.sort_order = #{sortOrder}
LIMIT 1

SELECT meaning_cn
FROM user_vocabulary_entries
WHERE user_id = #{userId}
  AND wordbook_id = #{wordbookId}
  AND id <> #{entryId}
ORDER BY RAND()
LIMIT 12
